#include <stdio.h>
#include <limits.h>

#define MAX_PROCESSES 10

typedef struct {
    int pid;
    int arrivalTime;
    int burstTime;
    int priority;
    int waitingTime;
    int turnaroundTime;
} Process;

void prioritySchedulerWithAging(Process processes[], int n) {
    int currentTime = 0;
    int completed = 0;
    int agingCounter[MAX_PROCESSES] = {0};

    while (completed < n) {
        int highestPriority = INT_MIN;
        int selectedProcess = -1;

        // Find process with highest effective priority (including aging)
        for (int i = 0; i < n; i++) {
            // Calculate effective priority with aging
            int effectivePriority = processes[i].priority + agingCounter[i];

            if (processes[i].arrivalTime <= currentTime &&
                effectivePriority > highestPriority &&
                processes[i].burstTime > 0) {
                highestPriority = effectivePriority;
                selectedProcess = i;
            }
        }

        if (selectedProcess == -1) {
            currentTime++;
            continue;
        }

        // Execute selected process
        processes[selectedProcess].waitingTime = currentTime - processes[selectedProcess].arrivalTime;
        currentTime += processes[selectedProcess].burstTime;
        processes[selectedProcess].turnaroundTime = currentTime - processes[selectedProcess].arrivalTime;
        processes[selectedProcess].burstTime = 0;
        completed++;

        // Reset aging counter for executed process
        agingCounter[selectedProcess] = 0;

        // Increase aging counters for waiting processes
        for (int i = 0; i < n; i++) {
            if (i != selectedProcess && processes[i].arrivalTime <= currentTime && processes[i].burstTime > 0) {
                agingCounter[i] += 1;  // Increase priority by 1 for each unit of waiting
            }
        }
    }

    // Print results
    float totalWaiting = 0, totalTurnaround = 0;
    printf("PID\tPriority\tWaiting\tTurnaround\n");
    for (int i = 0; i < n; i++) {
        printf("%d\t%d\t	%d\t%d\n",
               processes[i].pid, processes[i].priority,
               processes[i].waitingTime, processes[i].turnaroundTime);
        totalWaiting += processes[i].waitingTime;
        totalTurnaround += processes[i].turnaroundTime;
    }
    printf("Average Waiting Time: %.2f\n", totalWaiting/n);
    printf("Average Turnaround Time: %.2f\n", totalTurnaround/n);
}

int main() {
    Process processes[] = {
        {1, 0, 10, 1, 0, 0},
        {2, 1, 5, 3, 0, 0},
        {3, 2, 8, 2, 0, 0}
    };
    int n = sizeof(processes) / sizeof(processes[0]);

    prioritySchedulerWithAging(processes, n);
    return 0;
}
